| MCP:MKZ65S | plugins {
| MCP:MKZ65S |     id 'java-library'
| MCP:MKZ65S |     id 'org.springframework.boot' apply(false)
| MCP:MKZ65S |     id 'io.spring.dependency-management'
| MCP:MKZ65S |     id 'io.spring.javaformat' apply(false)
| MCP:MKZ65S |     id 'org.asciidoctor.jvm.convert' apply(false)
| MCP:MKZ65S | }
| MCP:MKZ65S | 
| MCP:MKZ65S | apply from: 'lint.gradle'
| MCP:MKZ65S | 
| MCP:MKZ65S | allprojects {
| MCP:MKZ65S |     group = "${projectGroup}"
| MCP:MKZ65S |     version = "${applicationVersion}"
| MCP:MKZ65S | 
| MCP:MKZ65S |     repositories {
| MCP:MKZ65S |         mavenCentral()
| MCP:MKZ65S |     }
| MCP:MKZ65S | }
| MCP:MKZ65S | 
| MCP:MKZ65S | subprojects {
| MCP:MKZ65S |     apply plugin: 'java-library'
| MCP:MKZ65S |     apply plugin: 'org.springframework.boot'
| MCP:MKZ65S |     apply plugin: 'io.spring.dependency-management'
| MCP:MKZ65S |     apply plugin: 'org.asciidoctor.jvm.convert'
| MCP:MKZ65S |     
| MCP:MKZ65S |     dependencyManagement {
| MCP:MKZ65S |         imports {
| MCP:MKZ65S |             mavenBom "org.springframework.cloud:spring-cloud-dependencies:${springCloudDependenciesVersion}"
| MCP:MKZ65S |         }
| MCP:MKZ65S |     }
| MCP:MKZ65S | 
| MCP:MKZ65S |     dependencies {
| MCP:MKZ65S |         annotationProcessor 'org.springframework.boot:spring-boot-configuration-processor'
| MCP:MKZ65S |         testImplementation 'org.springframework.boot:spring-boot-test'
| MCP:MKZ65S |         testImplementation 'org.junit.jupiter:junit-jupiter-api'
| MCP:MKZ65S |         testImplementation 'org.junit.jupiter:junit-jupiter-engine'
| MCP:MKZ65S |         testRuntimeOnly 'org.junit.platform:junit-platform-launcher'
| MCP:MKZ65S |         testImplementation 'org.assertj:assertj-core'
| MCP:MKZ65S |         testImplementation 'org.mockito:mockito-core'
| MCP:MKZ65S |     }
| MCP:MKZ65S | 
| MCP:MKZ65S |     java {
| MCP:MKZ65S |         toolchain {
| MCP:MKZ65S |             languageVersion = JavaLanguageVersion.of(project.javaVersion)
| MCP:MKZ65S |         }
| MCP:MKZ65S |     }
| MCP:MKZ65S | 
| MCP:MKZ65S |     bootJar.enabled = false
| MCP:MKZ65S |     jar.enabled = true
| MCP:MKZ65S | 
| MCP:MKZ65S |     test {
| MCP:MKZ65S |         useJUnitPlatform {
| MCP:MKZ65S |             excludeTags 'develop', 'restdocs'
| MCP:MKZ65S |         }
| MCP:MKZ65S |     }
| MCP:MKZ65S | 
| MCP:MKZ65S |     testing {
| MCP:MKZ65S |         suites {
| MCP:MKZ65S |             test {
| MCP:MKZ65S |                 targets {
| MCP:MKZ65S |                     unitTest {
| MCP:MKZ65S |                         testTask.configure {
| MCP:MKZ65S |                             group = 'verification'
| MCP:MKZ65S |                             useJUnitPlatform {
| MCP:MKZ65S |                                 excludeTags 'develop', 'context', 'restdocs'
| MCP:MKZ65S |                             }
| MCP:MKZ65S |                         }
| MCP:MKZ65S |                     }
| MCP:MKZ65S | 
| MCP:MKZ65S |                     contextTest {
| MCP:MKZ65S |                         testTask.configure {
| MCP:MKZ65S |                             group = 'verification'
| MCP:MKZ65S |                             useJUnitPlatform {
| MCP:MKZ65S |                                 includeTags 'context'
| MCP:MKZ65S |                             }
| MCP:MKZ65S |                         }
| MCP:MKZ65S |                     }
| MCP:MKZ65S | 
| MCP:MKZ65S |                     restDocsTest {
| MCP:MKZ65S |                         testTask.configure {
| MCP:MKZ65S |                             group = 'verification'
| MCP:MKZ65S |                             useJUnitPlatform {
| MCP:MKZ65S |                                 includeTags 'restdocs'
| MCP:MKZ65S |                             }
| MCP:MKZ65S |                         }
| MCP:MKZ65S |                     }
| MCP:MKZ65S | 
| MCP:MKZ65S |                     developTest {
| MCP:MKZ65S |                         testTask.configure {
| MCP:MKZ65S |                             group = 'verification'
| MCP:MKZ65S |                             useJUnitPlatform {
| MCP:MKZ65S |                                 includeTags 'develop'
| MCP:MKZ65S |                             }
| MCP:MKZ65S |                         }
| MCP:MKZ65S |                     }
| MCP:MKZ65S |                 }
| MCP:MKZ65S |             }
| MCP:MKZ65S |         }
| MCP:MKZ65S |     }
| MCP:MKZ65S | 
| MCP:MKZ65S |     tasks.named('asciidoctor').configure {
| MCP:MKZ65S |         dependsOn restDocsTest
| MCP:MKZ65S |     }
| MCP:MKZ65S | }

| MCP:MKZ65S | subprojects {
| MCP:MKZ65S |     apply plugin: 'java'
| MCP:MKZ65S |     apply plugin: 'io.spring.javaformat'
| MCP:MKZ65S | 
| MCP:MKZ65S |     dependencies {
| MCP:MKZ65S |         compileOnly "io.spring.javaformat:spring-javaformat-gradle-plugin:${springJavaFormatVersion}"
| MCP:MKZ65S |     }
| MCP:MKZ65S | }

| MCP:MKZ65S | dependencies {
| MCP:MKZ65S |     api 'org.springframework.boot:spring-boot-restdocs'
| MCP:MKZ65S |     api 'org.springframework.restdocs:spring-restdocs-mockmvc'
| MCP:MKZ65S |     compileOnly 'org.junit.jupiter:junit-jupiter-api'
| MCP:MKZ65S | }

| MCP:MKZ65S | package io.dodn.springboot.test.api;
| MCP:MKZ65S | 
| MCP:MKZ65S | import org.junit.jupiter.api.BeforeEach;
| MCP:MKZ65S | import org.junit.jupiter.api.Tag;
| MCP:MKZ65S | import org.junit.jupiter.api.extension.ExtendWith;
| MCP:MKZ65S | import org.springframework.restdocs.RestDocumentationContextProvider;
| MCP:MKZ65S | import org.springframework.restdocs.RestDocumentationExtension;
| MCP:MKZ65S | import org.springframework.restdocs.mockmvc.MockMvcRestDocumentation;
| MCP:MKZ65S | import org.springframework.test.web.servlet.MockMvc;
| MCP:MKZ65S | import org.springframework.test.web.servlet.setup.MockMvcBuilders;
| MCP:MKZ65S | 
| MCP:MKZ65S | @Tag("restdocs")
| MCP:MKZ65S | @ExtendWith(RestDocumentationExtension.class)
| MCP:MKZ65S | public abstract class RestDocsTest {
| MCP:MKZ65S | 
| MCP:MKZ65S |     protected MockMvc mockMvc;
| MCP:MKZ65S | 
| MCP:MKZ65S |     private RestDocumentationContextProvider restDocumentation;
| MCP:MKZ65S | 
| MCP:MKZ65S |     @BeforeEach
| MCP:MKZ65S |     public void setUp(RestDocumentationContextProvider restDocumentation) {
| MCP:MKZ65S |         this.restDocumentation = restDocumentation;
| MCP:MKZ65S |     }
| MCP:MKZ65S | 
| MCP:MKZ65S |     protected MockMvc mockController(Object controller) {
| MCP:MKZ65S |         return MockMvcBuilders.standaloneSetup(controller)
| MCP:MKZ65S |             .apply(MockMvcRestDocumentation.documentationConfiguration(restDocumentation))
| MCP:MKZ65S |             .build();
| MCP:MKZ65S |     }
| MCP:MKZ65S | 
| MCP:MKZ65S | }
